schema:
{
  "$schema": "http://json-schema.org/draft-04/schema#",
  "title": "Event source collection",
  "type": "array",
  "items": {
    "title": "Event source",
    "type": "object",
    "properties": {
      "id": {
        "description": "Unique identifier given by the server",
        "type": "integer"
      },
      "generatedIdentifier": {
        "description": "Unique id generated by the server.",
        "type": "string"
      },
      "name": {
        "description": "A name to identify the event source.",
        "type": "string"
      },
      "organizationId": {
        "description": "The organization.",
        "type": "integer"
      },
      "eventSourceTemplateId": {
        "description": "The event source template instantiated.",
        "type": "integer"
      },
      "public": {
        "description": "Make the event source available to everybody.",
        "type": "boolean"
      },
      "deletable": {
        "type": "boolean",
        "description": "Define if the event source can be deleted."
      },
      "configuration": {
        "description": "A valid JSON object.",
        "type": "object"
      }
    },
    "required": [
      "id",
      "eventSourceId",
      "name",
      "organizationId",
      "eventSourceTemplateId",
      "deletable",
      "configuration"
    ]
  }
}

{
    "$schema": "http://json-schema.org/draft-04/schema#",
    "type": "object",
    "additionalProperties": false,
    "properties": {
        "bulk_publishing": {
            "type": "boolean"
        },
        "links": {
            "type": "object",
            "additionalProperties": false,
            "properties": {
                "active_top_level_browse_page": {
                    "description": "The top-level browse page which is active",
                    "$ref": "#/definitions/guid_list",
                    "maxItems": 1
                },
                "facet_groups": {
                    "description": "Prototype-stage metadata tagging tree roots for this content item. A content item my belong to many facet groups without having any specific facet_values links.",
                    "$ref": "#/definitions/guid_list"
                },
                "facet_values": {
                    "description": "Prototype-stage metadata tagging values for this content item, a content item can be linked to many facet values from varying facet groups.",
                    "$ref": "#/definitions/guid_list"
                },
                "finder": {
                    "description": "Powers links from content back to finders the content is surfaced on",
                    "$ref": "#/definitions/guid_list"
                },
                "lead_organisations": {
                    "description": "DEPRECATED: A subset of organisations that should be emphasised in relation to this content item. All organisations specified here should also be part of the organisations array.",
                    "$ref": "#/definitions/guid_list"
                },
                "mainstream_browse_pages": {
                    "description": "Powers the /browse section of the site. These are known as sections in some legacy apps.",
                    "$ref": "#/definitions/guid_list"
                },
                "meets_user_needs": {
                    "description": "The user needs this piece of content meets.",
                    "$ref": "#/definitions/guid_list"
                },
                "ordered_related_items": {
                    "description": "Related items, can be any page on GOV.UK. Mostly used for mainstream content to power the sidebar. Ordering of the links is determined by the editor in Content Tagger.",
                    "$ref": "#/definitions/guid_list"
                },
                "ordered_related_items_overrides": {
                    "description": "Related items, can be any page on GOV.UK. Overrides 'more like this' automatically generated links in the beta navigation.",
                    "$ref": "#/definitions/guid_list"
                },
                "organisations": {
                    "description": "All organisations linked to this content item. This should include lead organisations.",
                    "$ref": "#/definitions/guid_list"
                },
                "original_primary_publishing_organisation": {
                    "description": "The organisation that published the original version of the page. Corresponds to the first of the 'Lead organisations' in Whitehall for the first edition, and is empty for all other publishing applications.",
                    "$ref": "#/definitions/guid_list"
                },
                "parent": {
                    "description": "The parent content item.",
                    "$ref": "#/definitions/guid_list",
                    "maxItems": 1
                },
                "policy_areas": {
                    "description": "A largely deprecated tag currently only used to power email alerts.",
                    "$ref": "#/definitions/guid_list"
                },
                "primary_publishing_organisation": {
                    "description": "The organisation that published the page. Corresponds to the first of the 'Lead organisations' in Whitehall, and is empty for all other publishing applications.",
                    "$ref": "#/definitions/guid_list",
                    "maxItems": 1
                },
                "related_topics": {
                    "$ref": "#/definitions/guid_list"
                },
                "second_level_browse_pages": {
                    "description": "All 2nd level browse pages under active_top_level_browse_page",
                    "$ref": "#/definitions/guid_list"
                },
                "suggested_ordered_related_items": {
                    "description": "New A/B test suggestions for related items. Used for displaying related content on most pages, except for step-by-step and fatality notices. Links and their ordering are determined by the machine learning algorithms included in this A/B test.",
                    "$ref": "#/definitions/guid_list"
                },
                "taxons": {
                    "description": "Prototype-stage taxonomy label for this content item",
                    "$ref": "#/definitions/guid_list"
                },
                "top_level_browse_pages": {
                    "description": "All top-level browse pages",
                    "$ref": "#/definitions/guid_list"
                },
                "topics": {
                    "description": "Powers the /topic section of the site. These are known as specialist sectors in some legacy apps.",
                    "$ref": "#/definitions/guid_list"
                }
            }
        },
        "previous_version": {
            "type": "string"
        }
    },
    "definitions": {
        "guid": {
            "type": "string",
            "pattern": "^[a-f0-9]{8}-[a-f0-9]{4}-[1-5][a-f0-9]{3}-[89ab][a-f0-9]{3}-[a-f0-9]{12}$"
        },
        "guid_list": {
            "type": "array",
            "items": {
                "$ref": "#/definitions/guid"
            },
            "_uniqueItems": true
        }
    }
}

{
    "$schema": "http://json-schema.org/draft-04/schema#",
    "type": "object",
    "properties": {
        "meta": {
            "type": "object",
            "properties": {
                "id": {
                    "type": "string",
                    "pattern": "^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$"
                },
                "type": {
                    "type": "string",
                    "enum": [
                        "EiffelTestCaseCanceledEvent"
                    ]
                },
                "version": {
                    "type": "string",
                    "enum": [
                        "3.0.0"
                    ],
                    "default": "3.0.0"
                },
                "time": {
                    "type": "integer"
                },
                "tags": {
                    "type": "array",
                    "items": {
                        "type": "string"
                    }
                },
                "source": {
                    "type": "object",
                    "properties": {
                        "domainId": {
                            "type": "string"
                        },
                        "host": {
                            "type": "string"
                        },
                        "name": {
                            "type": "string"
                        },
                        "serializer": {
                            "type": "string",
                            "pattern": "^pkg:"
                        },
                        "uri": {
                            "type": "string"
                        }
                    },
                    "additionalProperties": false
                },
                "security": {
                    "type": "object",
                    "properties": {
                        "authorIdentity": {
                            "type": "string"
                        },
                        "integrityProtection": {
                            "type": "object",
                            "properties": {
                                "signature": {
                                    "type": "string"
                                },
                                "alg": {
                                    "type": "string",
                                    "enum": [
                                        "HS256",
                                        "HS384",
                                        "HS512",
                                        "RS256",
                                        "RS384",
                                        "RS512",
                                        "ES256",
                                        "ES384",
                                        "ES512",
                                        "PS256",
                                        "PS384",
                                        "PS512"
                                    ]
                                },
                                "publicKey": {
                                    "type": "string"
                                }
                            },
                            "required": [
                                "signature",
                                "alg"
                            ],
                            "additionalProperties": false
                        },
                        "sequenceProtection": {
                            "type": "array",
                            "items": {
                                "type": "object",
                                "properties": {
                                    "sequenceName": {
                                        "type": "string"
                                    },
                                    "position": {
                                        "type": "integer"
                                    }
                                },
                                "additionalProperties": false,
                                "required": [
                                    "sequenceName",
                                    "position"
                                ]
                            }
                        }
                    },
                    "additionalProperties": false,
                    "required": [
                        "authorIdentity"
                    ]
                }
            },
            "required": [
                "id",
                "type",
                "version",
                "time"
            ],
            "additionalProperties": false
        },
        "data": {
            "type": "object",
            "properties": {
                "reason": {
                    "type": "string"
                },
                "customData": {
                    "type": "array",
                    "items": {
                        "type": "object",
                        "properties": {
                            "key": {
                                "type": "string"
                            },
                            "value": {}
                        },
                        "required": [
                            "key",
                            "value"
                        ],
                        "additionalProperties": false
                    }
                }
            },
            "additionalProperties": false
        },
        "links": {
            "type": "array",
            "items": {
                "type": "object",
                "properties": {
                    "type": {
                        "type": "string"
                    },
                    "target": {
                        "type": "string",
                        "pattern": "^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$"
                    }
                },
                "required": [
                    "type",
                    "target"
                ],
                "additionalProperties": false
            }
        }
    },
    "required": [
        "meta",
        "data",
        "links"
    ],
    "additionalProperties": false
}
